from harness.context import CaseContext
from harness.runner import run_matrix


def test_bound_contexts_and_repeated_probe_names_keep_target_identity():
    root = CaseContext()
    first = root.bind("alpha")
    second = root.bind("beta")

    assert first is not second
    assert (first.case_id, second.case_id) == ("alpha", "beta")

    results = run_matrix(
        ["alpha", "beta"],
        [("reachable", lambda context: context.case_id == "alpha")],
    )
    observed = {
        (item.case_id, item.check_name): item.passed for item in results
    }

    assert observed == {
        ("alpha", "reachable"): True,
        ("beta", "reachable"): False,
    }
